import{r as e,o as r,c as i,a,w as n,F as l,b as o,d as t}from"./app.2e1eaa90.js";const d={},s=a("h1",{id:"事件-events",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#事件-events","aria-hidden":"true"},"#"),o(" 事件 (Events)")],-1),c=o("建议配套阅读："),h=o("事件与生命周期"),g=t('<h2 id="上报事件" tabindex="-1"><a class="header-anchor" href="#上报事件" aria-hidden="true">#</a> 上报事件</h2><p>所有的上报事件都是通过 emit 方式在对应的上下文中触发的（即上下文选择器对这些事件有效，且回调函数的返回值不会影响后续行为）。</p><h3 id="通用会话属性" tabindex="-1"><a class="header-anchor" href="#通用会话属性" aria-hidden="true">#</a> 通用会话属性</h3><p>以下属性对所有会话都有：</p><ul><li><strong>type:</strong> <code>string</code> 事件名称</li><li><strong>subtype:</strong> <code>string</code> 一级子事件名称</li><li><strong>subsubtype:</strong> <code>string</code> 二级子事件名称</li><li><strong>platform:</strong> <code>string</code> 产生事件的平台</li><li><strong>selfId:</strong> <code>string</code> 收到事件的机器人的平台 ID</li><li><strong>userId:</strong> <code>string</code> 触发事件的用户的平台 ID</li><li><strong>groupId:</strong> <code>string</code> 触发事件的群组的平台 ID</li><li><strong>channelId:</strong> <code>string</code> 触发事件的频道的平台 ID</li><li><strong>timestamp:</strong> <code>number</code> 收到事件的 UNIX 时间，单位为毫秒</li></ul><h3 id="消息类事件" tabindex="-1"><a class="header-anchor" href="#消息类事件" aria-hidden="true">#</a> 消息类事件</h3><p>跟消息有关的几种事件统称为消息类事件，共有以下几种：</p><ul><li>message: 收到新消息</li><li>message-deleted: 消息被删除</li><li>message-updated: 消息被修改</li><li>send: 机器人发出消息</li></ul><p>这些事件都还拥有以下的子事件：</p><ul><li>private: 该消息是私聊消息</li><li>group: 该消息是群组消息</li></ul><p>与此类事件相关的属性有：</p><ul><li><strong>messageId:</strong> <code>string</code> 消息 ID</li><li><strong>content:</strong> <code>string</code> 消息内容</li><li><strong>author:</strong> 发送者信息 <ul><li><strong>author.userId:</strong> <code>string</code> 发送者的平台 ID</li><li><strong>author.avatar:</strong> <code>string</code> 发送者的头像链接</li><li><strong>author.username:</strong> <code>string</code> 发送者的平台昵称</li><li><strong>author.nickname:</strong> <code>string</code> 发送者在当前群组中的昵称</li></ul></li><li><strong>quote:</strong> 引用的消息，同样包含 <code>messageId</code>, <code>content</code> 等属性</li></ul><h3 id="成员类事件" tabindex="-1"><a class="header-anchor" href="#成员类事件" aria-hidden="true">#</a> 成员类事件</h3><p>跟群组、好友有关的事件统称为成员类事件，共有以下几种：</p><ul><li>group-added: 加入了群组</li><li>group-deleted: 退出了群组</li><li>group-request: 收到了群组邀请</li><li>group-member-added: 群组成员增加</li><li>group-member-deleted: 群组成员减少</li><li>group-member-request: 收到了入群申请</li><li>friend-added: 好友数量增加</li><li>friend-deleted: 好友数量减少</li><li>friend-request: 收到了好友请求</li></ul><p>形如 group(-member)?-(added|deleted) 的事件拥有以下的子事件：</p><ul><li>active: 该操作是由加入或退出方发起的</li><li>passive: 该操作是群组方发起的</li></ul><p>形如 group(-member)?-(added|deleted) 的事件拥有以下的属性：</p><ul><li><strong>operatorId:</strong> <code>string</code> 操作者 ID</li></ul><p>以 request 结尾的事件拥有下面的属性：</p>',20),u=a("strong",null,"messageId:",-1),p=o(),f=a("code",null,"string",-1),b=o(" 请求 ID，可用于 "),m=o("Bot"),x=o(" 方法"),I=a("li",null,[a("strong",null,"content:"),o(),a("code",null,"string"),o(" 请求文本")],-1),v=t('<h3 id="操作类事件" tabindex="-1"><a class="header-anchor" href="#操作类事件" aria-hidden="true">#</a> 操作类事件</h3><p>上报事件中最主要的一部分都有着统一的结构：<strong>事件主体</strong> + <strong>操作类型</strong>。例如好友请求事件是 friend-request，群组文件更新事件是 group-file-updated 等。目前支持的事件主体包括以下几种：</p><ul><li>friend</li><li>channel</li><li>group</li><li>group-member</li><li>group-role</li><li>group-file</li><li>group-emoji</li></ul><p>操作类型包含以下几种：</p><ul><li>added</li><li>removed</li><li>deleted</li></ul><h3 id="群成员类事件" tabindex="-1"><a class="header-anchor" href="#群成员类事件" aria-hidden="true">#</a> 群成员类事件</h3><h3 id="通知类事件" tabindex="-1"><a class="header-anchor" href="#通知类事件" aria-hidden="true">#</a> 通知类事件</h3><p>由系统在频道中发送的各种通知构成了通知类事件，共有以下几种：</p><ul><li>notice/poke: 戳一戳</li><li>notice/lucky-king: 运气王</li><li>notice/honor: 群荣誉</li></ul><p>与此类事件相关的属性有：</p><ul><li><strong>targetId:</strong> <code>string</code> 戳一戳的目标用户 ID，运气王的获得者 ID</li><li><strong>honorType:</strong> <code>string</code> 荣誉类型，可能为 talkative, performer, emotion</li></ul><h2 id="内部事件" tabindex="-1"><a class="header-anchor" href="#内部事件" aria-hidden="true">#</a> 内部事件</h2><p>若非特别说明，这里的所有事件在全体上下文触发的（即上下文选择器对这些事件无效）。</p><h3 id="事件-before-connect" tabindex="-1"><a class="header-anchor" href="#事件-before-connect" aria-hidden="true">#</a> 事件：before-connect</h3><ul><li><strong>触发方式:</strong> parallel</li></ul><p>开始连接到服务器时触发。</p><h3 id="事件-connect" tabindex="-1"><a class="header-anchor" href="#事件-connect" aria-hidden="true">#</a> 事件：connect</h3><ul><li><strong>触发方式:</strong> emit</li></ul><p>成功连接到服务器时触发。如果一个插件在注册时，应用已经处于连接状态，则会立即触发。</p><h3 id="事件-before-parse" tabindex="-1"><a class="header-anchor" href="#事件-before-parse" aria-hidden="true">#</a> 事件：before-parse</h3><ul><li><strong>content:</strong> <code>string</code> 要解析的文本</li><li><strong>session:</strong> <code>Session</code> 当前会话</li><li><strong>触发方式:</strong> bail</li></ul><p>尝试将文本解析成 Argv 对象时调用。你可以在回调函数中返回一个 Argv 对象以覆盖默认的解析行为。</p><h3 id="事件-parse" tabindex="-1"><a class="header-anchor" href="#事件-parse" aria-hidden="true">#</a> 事件：parse</h3><ul><li><strong>argv:</strong> <code>Argv</code> 运行时参数</li><li><strong>触发方式:</strong> bail</li></ul><p>尝试将一个未识别出指令的 Argv 对象识别成指令调用时使用。你可以在回调函数中修改传入的 Argv 对象，或者返回一个字符串表示识别出的指令。</p><h3 id="事件-before-attach-channel" tabindex="-1"><a class="header-anchor" href="#事件-before-attach-channel" aria-hidden="true">#</a> 事件：before-attach-channel</h3><h3 id="事件-before-attach-user" tabindex="-1"><a class="header-anchor" href="#事件-before-attach-user" aria-hidden="true">#</a> 事件：before-attach-user</h3><ul><li><strong>session:</strong> <code>Session</code> 当前会话</li><li><strong>fields:</strong> <code>Set&lt;string&gt;</code> 要获取的字段列表</li><li><strong>触发方式:</strong> emit</li></ul><p>当 Koishi 试图从数据库获取频道 / 用户信息前触发。你可以在回调函数中通过 <code>fields.add()</code> 修改传入的字段集合，增加的字段将可以被指令以及之后的中间件获取到。</p><p>如果没有配置数据库，则两个事件都不会触发；如果不是群聊消息，则 before-attach-channel 事件不会触发。</p><h3 id="事件-attach-channel" tabindex="-1"><a class="header-anchor" href="#事件-attach-channel" aria-hidden="true">#</a> 事件：attach-channel</h3><h3 id="事件-attach-user" tabindex="-1"><a class="header-anchor" href="#事件-attach-user" aria-hidden="true">#</a> 事件：attach-user</h3><ul><li><strong>session:</strong> <code>Session</code> 当前会话</li><li><strong>触发方式:</strong> serial</li></ul><p>当 Koishi 完成频道 / 用户数据获取后触发。调用时会传入一个 Session 对象，将会拥有 <code>channel</code>/<code>user</code> 属性。你可以在回调函数中修改这两个属性，这些修改会在后续过程中自动更新到数据库。如果你在回调函数中返回一个 truthy 值，则该会话不会触发指令以及之后的中间件。</p><p>如果没有配置数据库，则两个事件都不会触发；如果不是群聊消息，则 attach-channel 事件不会触发。</p><h3 id="事件-before-send" tabindex="-1"><a class="header-anchor" href="#事件-before-send" aria-hidden="true">#</a> 事件：before-send</h3><ul><li><strong>session:</strong> <code>Session</code> 消息会话</li><li><strong>触发方式:</strong> bail</li></ul><p>即将发送信息时会在对应的上下文触发。调用时会传入一个事件类型为 <a href="#%E6%B6%88%E6%81%AF%E7%B1%BB%E4%BA%8B%E4%BB%B6">send</a> 的会话实例。由于该消息还未发送，这个会话并没有 <code>messageId</code> 属性。你可以通过修改 <code>session.content</code> 改变发送的内容，或者返回一个 truthy 值以取消该消息的发送。</p><h3 id="事件-before-command" tabindex="-1"><a class="header-anchor" href="#事件-before-command" aria-hidden="true">#</a> 事件：before-command</h3><ul><li><strong>argv:</strong> <code>Argv</code> 运行时参数</li><li><strong>触发方式:</strong> serial</li></ul><p>调用指令前会在对应的上下文触发。此时指令的可用性还未经检测，因此可能出现参数错误、权限不足、超过使用次数等情况。你可以通过在回调函数中返回一个字符串以取消该指令的执行。进一步，如果该字符串非空，则会作为此指令执行的结果。</p><h3 id="事件-command" tabindex="-1"><a class="header-anchor" href="#事件-command" aria-hidden="true">#</a> 事件：command</h3><ul><li><strong>argv:</strong> <code>Argv</code> 运行时参数</li><li><strong>触发方式:</strong> parallel</li></ul><p>指令调用完毕后会在对应的上下文触发。</p><h3 id="事件-middleware" tabindex="-1"><a class="header-anchor" href="#事件-middleware" aria-hidden="true">#</a> 事件：middleware</h3><ul><li><strong>session:</strong> <code>Session</code> 当前会话</li><li><strong>触发方式:</strong> emit</li></ul><p>在执行完全部中间件后会在对应的上下文触发。</p><h3 id="事件-before-disconnect" tabindex="-1"><a class="header-anchor" href="#事件-before-disconnect" aria-hidden="true">#</a> 事件：before-disconnect</h3><ul><li><strong>触发方式:</strong> parallel</li></ul>',49),B=o("关闭服务器前，或所属插件被卸载时触发。参见 "),E=o("可卸载的插件"),A=o("。"),D=a("h3",{id:"事件-disconnect",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#事件-disconnect","aria-hidden":"true"},"#"),o(" 事件：disconnect")],-1),y=a("ul",null,[a("li",null,[a("strong",null,"触发方式:"),o(" emit")])],-1),S=a("p",null,"成功关闭服务器后触发。",-1);d.render=function(o,t){const d=e("RouterLink");return r(),i(l,null,[s,a("p",null,[c,a(d,{to:"/guide/lifecycle.html"},{default:n((()=>[h])),_:1})]),g,a("ul",null,[a("li",null,[u,p,f,b,a(d,{to:"/api/bot.html#%E5%A4%84%E7%90%86%E8%AF%B7%E6%B1%82"},{default:n((()=>[m])),_:1}),x]),I]),v,a("p",null,[B,a(d,{to:"/guide/context.html#%E5%8F%AF%E5%8D%B8%E8%BD%BD%E7%9A%84%E6%8F%92%E4%BB%B6"},{default:n((()=>[E])),_:1}),A]),D,y,S],64)};export default d;
